// Parse incoming ticket (from GitHub Issues webhook or manual POST)
const body = $input.first().json;

const ticket = {
  id: body.issue?.number || body.ticketId || 'JIRA-482',
  title: body.issue?.title || body.title || 'New PostgreSQL DB for ad-analytics service',
  body: body.issue?.body || body.description || '',
  requestedBy: body.sender?.login || body.requestedBy || 'prakhar',
  timestamp: new Date().toISOString()
};

// Extract resource type from title
const lower = ticket.title.toLowerCase();
let resourceType = 'generic';
if (lower.includes('postgres') || lower.includes('database') || lower.includes('db')) resourceType = 'postgresql';
else if (lower.includes('s3') || lower.includes('blob') || lower.includes('storage')) resourceType = 'storage';
else if (lower.includes('vm') || lower.includes('virtual machine')) resourceType = 'vm';
else if (lower.includes('redis') || lower.includes('cache')) resourceType = 'redis';

return [{ json: { ...ticket, resourceType } }];

// Generate Terraform based on resource type
const data = $input.first().json;

const templates = {
  postgresql: `# Auto-generated by IaC Agent | Ticket: ${data.id}
# Requested by: ${data.requestedBy} | ${data.timestamp}

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>3.0"
    }
  }
}

provider "azurerm" {
  features {}
}

resource "azurerm_postgresql_flexible_server" "main" {
  name                   = "waresmedia-psql-${data.id.toLowerCase().replace(/[^a-z0-9]/g, '-')}"
  resource_group_name    = var.resource_group_name
  location               = var.location
  version                = "14"
  administrator_login    = var.db_admin_user
  administrator_password = var.db_admin_password
  zone                   = "1"

  storage_mb = 32768

  sku_name = "B_Standard_B1ms"

  tags = {
    environment = "production"
    team        = "devops"
    ticket      = "${data.id}"
    managed_by  = "iac-agent"
  }
}

resource "azurerm_postgresql_flexible_server_database" "main" {
  name      = "ad-analytics"
  server_id = azurerm_postgresql_flexible_server.main.id
  collation = "en_US.utf8"
  charset   = "utf8"
}

variable "resource_group_name" { default = "waresmedia-prod" }
variable "location" { default = "Central India" }
variable "db_admin_user" { default = "dbadmin" }
variable "db_admin_password" { sensitive = true }`,

  storage: `# Auto-generated by IaC Agent | Ticket: ${data.id}

resource "azurerm_storage_account" "main" {
  name                     = "waresmedia${data.id.toLowerCase().replace(/[^a-z0-9]/g, '')}"
  resource_group_name      = var.resource_group_name
  location                 = var.location
  account_tier             = "Standard"
  account_replication_type = "LRS"

  tags = {
    ticket     = "${data.id}"
    managed_by = "iac-agent"
  }
}`,

  vm: `# Auto-generated by IaC Agent | Ticket: ${data.id}

resource "azurerm_linux_virtual_machine" "main" {
  name                = "waresmedia-vm-${data.id.toLowerCase().replace(/[^a-z0-9]/g, '-')}"
  resource_group_name = var.resource_group_name
  location            = var.location
  size                = "Standard_B1s"
  admin_username      = "azureuser"

  tags = {
    ticket     = "${data.id}"
    managed_by = "iac-agent"
  }
}`,

  generic: `# Auto-generated by IaC Agent | Ticket: ${data.id}
# Resource type could not be auto-detected
# Please review and complete this template

# TODO: Define your resource here`
};

const terraform = templates[data.resourceType] || templates.generic;

// Simulate terraform plan output
const planOutput = `Terraform will perform the following actions:

  # azurerm_postgresql_flexible_server.main will be created
  + resource "azurerm_postgresql_flexible_server" "main" {
      + id                   = (known after apply)
      + name                 = "waresmedia-psql-${data.id.toLowerCase().replace(/[^a-z0-9]/g, '-')}"
      + location             = "Central India"
      + sku_name             = "B_Standard_B1ms"
      + storage_mb           = 32768
    }

Plan: 2 to add, 0 to change, 0 to destroy.`;

return [{ json: { ...data, terraform, planOutput, status: 'awaiting_approval' } }];

// Write pending approval to Azure Blob so dashboard can read it
const data = $input.first().json;

const approvalRecord = {
  id: `approval-${data.id}-${Date.now()}`,
  agentId: 'iac-gen',
  agentName: 'IaC Generation Agent',
  ticketId: data.id,
  ticketTitle: data.title,
  requestedBy: data.requestedBy,
  resourceType: data.resourceType,
  terraform: data.terraform,
  planOutput: data.planOutput,
  status: 'pending',
  createdAt: new Date().toISOString(),
  approveWebhook: `http://YOUR_VM_IP:5678/webhook/approve-iac`,
  rejectWebhook: `http://YOUR_VM_IP:5678/webhook/reject-iac`
};

return [{ json: approvalRecord }];

// Simulate terraform apply after approval
const incomingData = $input.first().json;

// Extracting from the inner body block safely
const webhookBody = incomingData.body || {};

await new Promise(r => setTimeout(r, 2000));

// Safely pull fields or assign defaults
const ticketId = webhookBody.ticketId || "UNKNOWN-TICKET";
const approvalId = webhookBody.approvalId || "NO-ID";
const approvedBy = webhookBody.approvedBy || "prakhar";

// Formatting string safely
const safeTicketString = ticketId.toLowerCase().replace(/[^a-z0-9]/g, '-');

const applyResult = {
  approvalId: approvalId,
  ticketId: ticketId,
  approvedBy: approvedBy,
  appliedAt: new Date().toISOString(),
  status: 'applied',
  outputs: {
    db_host: `cloudopsstoragepp-psql-${safeTicketString}.postgres.database.azure.com`,
    db_name: 'ad-analytics',
    db_port: 5432,
    ticketId: ticketId
  }
};

return [{ json: applyResult }];

