const d = $json;

return [{
  json: {
    ...d,
    slackMessage:
`✅ *IaC Agent* | Terraform applied successfully
> Ticket: ${d.ticketId}
> Approved by: ${d.approvedBy}
> DB Host: \`${d.outputs.db_host}\`
> DB: ${d.outputs.db_name} | Port: ${d.outputs.db_port}`
  }
}];
